#include <iostream>

int main() {
    const int squares_per_side = 8;
    const int total_squares = squares_per_side * squares_per_side;
    const int max_piece_value = 9 + 5 + 5 + 3 + 3 + 14;

    std::cout << "Squares per side: " << squares_per_side << "\n";
    std::cout << "Total squares: " << total_squares << "\n";
    std::cout << "Max piece value: " << max_piece_value << "\n";
    return 0;
}

